import React from 'react';
import Slider from 'react-slick';
//Estilos
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";

const settings = {
    dots: true,
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    autoplay: true,
    autoplaySpeed: 5000,
    vertical: true,
    prevArrow: <CustomPrevArrow />, // Flecha personalizada previa
    nextArrow: <CustomNextArrow />, // Flecha personalizada siguiente
};

const MiSlider = () => {
  const settings = {
    dots: true,
    arrows: true,
    // Resto de opciones del slider
    prevArrow: <CustomPrevArrow />, // Flecha personalizada previa
    nextArrow: <CustomNextArrow />, // Flecha personalizada siguiente
  };

  // Componente de flecha personalizada previa
  const CustomPrevArrow = ({ onClick }) => (
    <div onClick={onClick} style={{ color: 'red' }}>
      Prev
    </div>
  );

  // Componente de flecha personalizada siguiente
  const CustomNextArrow = ({ onClick }) => (
    <div onClick={onClick} style={{ color: 'blue' }}>
      Next
    </div>
  );

  return (
    <Slider {...settings}>
      <div>
        <h3>Slide 1</h3>
      </div>
      <div>
        <h3>Slide 2</h3>
      </div>
      <div>
        <h3>Slide 3</h3>
      </div>
    </Slider>
  );
};

export default MiSlider;
